// Extract top-10 organic results and prepare for analysis
const serpData = $input.first().json;
const keyword = $('Split Keywords').first().json.keyword;

const organicResults = (serpData.organic_results || []).slice(0, 10).map((r, i) => ({
  position: r.position || i + 1,
  title: r.title || '',
  url: r.link || '',
  domain: (r.displayed_link || '').split('/')[0],
  snippet: r.snippet || ''
}));

return [{
  json: {
    keyword,
    timestamp: new Date().toISOString(),
    results_count: organicResults.length,
    competitors: organicResults,
    competitors_summary: organicResults.map(r => `${r.position}. ${r.domain}: ${r.title}`).join('\n')
  }
}];

