// Format the final report for email
const analysisResponse = $input.first().json;
const keyword = $('Extract Competitor Data').first().json.keyword;
const competitors = $('Extract Competitor Data').first().json.competitors;
const timestamp = $('Extract Competitor Data').first().json.timestamp;

// Extract Claude's response text
const analysisText = analysisResponse?.content?.[0]?.text || 'Analysis unavailable';

// Build competitor table
const competitorTable = competitors.map(c =>
  `<tr><td style="padding:4px 8px">#${c.position}</td><td style="padding:4px 8px">${c.domain}</td><td style="padding:4px 8px">${c.title}</td></tr>`
).join('');

// Build HTML report
const htmlReport = `
<html><body style="font-family: Arial, sans-serif; max-width: 700px; margin: 0 auto;">
  <div style="background: #1a1a2e; color: white; padding: 20px; border-radius: 8px 8px 0 0;">
    <h1 style="margin:0; font-size: 20px;">SEO Competitive Intelligence Report</h1>
    <p style="margin: 5px 0 0; opacity: 0.7;">Generated: ${new Date(timestamp).toLocaleDateString('en-GB')}</p>
  </div>
  <div style="padding: 20px; background: #f9f9f9; border: 1px solid #ddd;">
    <h2 style="color: #1a1a2e;">Keyword: "${keyword}"</h2>
    <h3 style="color: #e74c3c;">🎯 Content Gap Analysis</h3>
    <div style="background: white; padding: 15px; border-left: 4px solid #e74c3c; border-radius: 4px;">
      ${analysisText.replace(/\n/g, '<br>')}
    </div>
    <h3 style="color: #2c3e50;">Top-10 SERP Competitors</h3>
    <table style="width: 100%; border-collapse: collapse; background: white;">
      <tr style="background: #2c3e50; color: white;">
        <th style="padding: 8px;">Pos</th>
        <th style="padding: 8px;">Domain</th>
        <th style="padding: 8px;">Title</th>
      </tr>
      ${competitorTable}
    </table>
    <p style="color: #7f8c8d; font-size: 12px; margin-top: 20px;">
      This report is automatically generated by SEO Intelligence Hub.<br>
      Every AI call is logged and monitored in LangSmith for transparency.
    </p>
  </div>
</body></html>`;

return [{
  json: {
    keyword,
    timestamp,
    subject: `SEO Report: "${keyword}" — ${competitors.length} competitors analyzed`,
    html_report: htmlReport,
    analysis_text: analysisText
  }
}];

